slides.codeSnippet:
mixin Jumper {
  void jump() => print('Jumping high!');
}

mixin Runner {
  void run() => print('Running fast!');
}

// We attach BOTH superpowers to the Athlete!
class Athlete with Jumper, Runner {}

void main() {
  Athlete usain = Athlete();
  usain.run();
  usain.jump();
}
